Let $A,$ $B,$ $C,$ $n,$ and $l$ be as in the diagram below.


[asy]
        size(175);
        draw(circle((0,5),5),black+linewidth(1));
        pair A=(1,5+4*sqrt(13/2)), B=(5+2*sqrt(13/2),5), C=(5-2*sqrt(13/2),5), P=(5,5+sqrt(13/2)), Q=(5,5);
        draw((8/5)*A--(8/5)*B-- shifts((8/5)*(B-A))*dir(36.87))* white;
        clip((0,0)--(0,20)--(50,20)--(50,0)--(0,0));
